const isBlockPattern = (liveCells: Array<[number, number]>): boolean => {
  // Check if liveCells form one or more 2x2 block patterns
  if (liveCells.length === 0 || liveCells.length % 4 !== 0) return false;

  // Group cells by blocks and verify each is a 2x2 block
  const blocks: Map<string, Array<[number, number]>> = new Map();

  for (const [x, y] of liveCells) {
    const blockKey = `${Math.floor(x / 2)},${Math.floor(y / 2)}`;
    if (!blocks.has(blockKey)) {
      blocks.set(blockKey, []);
    }
    blocks.get(blockKey)!.push([x, y]);
  }

  // Each block must have exactly 4 cells forming a 2x2 square
  for (const blockCells of blocks.values()) {
    if (blockCells.length !== 4) return false;

    // Sort and check if they form a 2x2 square
    blockCells.sort((a, b) => a[0] - b[0] || a[1] - b[1]);
    const minX = blockCells[0][0];
    const minY = blockCells[0][1];

    const expected = [
      [minX, minY],
      [minX, minY + 1],
      [minX + 1, minY],
      [minX + 1, minY + 1]
    ];

    if (!expected.every(([ex, ey], i) => blockCells[i][0] === ex && blockCells[i][1] === ey)) {
      return false;
    }
  }

  return true;
};

