  // Check if liveCells form one or more 2x2 block patterns
  if (liveCells.length === 0 || liveCells.length % 4 !== 0) return false;

  // Create a set for fast lookup
  const cellSet = new Set(liveCells.map(([x, y]) => `${x},${y}`));

