  const checked = new Set<string>();

  for (const [x, y] of liveCells) {
    const blockKey = `${Math.min(x, x + 1)},${Math.min(y, y + 1)}`;
    if (checked.has(blockKey)) continue;
    checked.add(blockKey);

    // Check if this forms a 2x2 block
    const minX = Math.min(x, x + 1);
    const minY = Math.min(y, y + 1);

    const block = [
      [minX, minY],
      [minX, minY + 1],
      [minX + 1, minY],
      [minX + 1, minY + 1]
    ];

    const hasAllCells = block.every(([bx, by]) => cellSet.has(`${bx},${by}`));
    if (!hasAllCells) return false;
  }

  return checked.size * 4 === liveCells.length;
};

